func arcaDocTypeLetter(ext tax.Extensions) (string, string) {
	if ext == nil {
		return "", ""
	}
	dt := ext[arca.ExtKeyDocType]
	if dt.IsEmpty() {
		return "", ""
	}
	code := cbc.Code(dt.String())
	var letter string
	switch {
	case slices.Contains(arca.DocTypesA, code):
		letter = "A"
	case slices.Contains(arca.DocTypesB, code):
		letter = "B"
	case slices.Contains(arca.DocTypesC, code):
		letter = "C"
	default:
		return "", ""
	}
	return letter, fmt.Sprintf("Cod. %s", dt.String())
}

